eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   story: () => (/* binding */ story)\n/* harmony export */ });\nconst story = {\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    // CAPÍTULO 1 — \"INSÔNIA\"\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    \"ch1-001\": {\n        id: \"ch1-001\",\n        background: \"quarto-ella-noite\",\n        transition: \"fade\",\n        chapter: \"ch1\",\n        chapterTitle: \"INS\\xd4NIA\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Ella acordou. N\\xe3o lembrava de estar dormindo. Acordava sempre sem lembrar — como se o sono fosse um hiato que preenchia sem consentimento, um par\\xeantese que sua mente rejeitava.\",\n        next: \"ch1-002\"\n    },\n    \"ch1-002\": {\n        id: \"ch1-002\",\n        speaker: null,\n        text: \"2h17. O rel\\xf3gio na parede dizia isso com a precis\\xe3o de quem conta os segundos por contar. A chuva batia na janela. Gotas irregulares que soavam como dedos impacientes.\",\n        next: \"ch1-003\"\n    },\n    \"ch1-003\": {\n        id: \"ch1-003\",\n        speaker: null,\n        text: \"O quarto rosa — aquele rosa fosco e deliberado que Ella tinha escolhido quando tinha 14 anos — era cinza sob a escurid\\xe3o. Os posters na parede viravam sombras. Os nendoroids na prateleira eram silhuetas sem detalhes.\",\n        next: \"ch1-004\"\n    },\n    \"ch1-004\": {\n        id: \"ch1-004\",\n        speaker: null,\n        text: \"Voc\\xea sabe aquele sentimento de que algo a acordou? N\\xe3o um barulho exato. Mais uma press\\xe3o. Uma aten\\xe7\\xe3o que voc\\xea sente mesmo antes de entender o que a criou.\",\n        next: \"ch1-005\"\n    },\n    \"ch1-005\": {\n        id: \"ch1-005\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: null,\n        text: \"Ella levantou. Ficou parada um momento com os p\\xe9s descal\\xe7os no ch\\xe3o frio. Depois saiu do quarto em sil\\xeancio, o cobertor ainda nos ombros como um fantasma que n\\xe3o tinha coragem de ir embora.\",\n        next: \"ch1-006\"\n    },\n    \"ch1-006\": {\n        id: \"ch1-006\",\n        background: \"corredor-dormitorios-noite\",\n        transition: \"fade\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"O corredor dos dormit\\xf3rios \\xe0 noite \\xe9 um lugar que n\\xe3o deveria existir. \\xc9 um lugar entre — entre os quartos privados e o resto da casa. Entre o sono e a vig\\xedlia.\",\n        next: \"ch1-007\"\n    },\n    \"ch1-007\": {\n        id: \"ch1-007\",\n        speaker: null,\n        text: \"Ella caminhou descal\\xe7a. Seus p\\xe9s conheciam cada t\\xe1bua que rangeria e cada uma que n\\xe3o faria barulho.\",\n        next: \"ch1-008\"\n    },\n    \"ch1-008\": {\n        id: \"ch1-008\",\n        speaker: null,\n        text: \"143 dias sem Niuw\\xeb. Ela contava em caf\\xe9s da manh\\xe3. Em passagens pela est\\xe1tua. Em tardes onde a aus\\xeancia tinha o peso espec\\xedfico de quem deveria estar presente e n\\xe3o estava.\",\n        next: \"ch1-009\"\n    },\n    \"ch1-009\": {\n        id: \"ch1-009\",\n        background: \"cozinha-ella-noite\",\n        transition: \"fade\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"looking-away\"\n            }\n        },\n        speaker: null,\n        text: \"A cozinha. Ella abriu a geladeira. A luz interna foi a \\xfanica coisa branca no lugar por um instante.\",\n        next: \"ch1-010\"\n    },\n    \"ch1-010\": {\n        id: \"ch1-010\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"\\xc1gua fria. Era tudo que ela buscava neste momento.\",\n        next: \"ch1-011\"\n    },\n    \"ch1-011\": {\n        id: \"ch1-011\",\n        sprites: {\n            center: null\n        },\n        speaker: null,\n        text: \"A geladeira fechou. A escurid\\xe3o voltou. E nela, um som. Passos no corredor. Descal\\xe7os. Leves.\",\n        next: \"ch1-012\"\n    },\n    \"ch1-012\": {\n        id: \"ch1-012\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"surprised\"\n            }\n        },\n        speaker: null,\n        text: \"Ella congelou. N\\xe3o pela frio. Pelo repentino reconhecimento de n\\xe3o estar sozinha.\",\n        sound: \"silence\",\n        choices: [\n            {\n                text: \"Abrir a porta e verificar\",\n                next: \"ch1-020\",\n                setFlag: \"abrir-porta=true\"\n            },\n            {\n                text: \"Ficar aqui e ignorar\",\n                next: \"ch1-030\",\n                setFlag: \"ignorar-barulho=true\"\n            }\n        ]\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // CAMINHO A: Abrir a porta e verificar → Encontra Marci primeiro\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch1-020\": {\n        id: \"ch1-020\",\n        background: \"corredor-dormitorios-noite\",\n        transition: \"fade\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"surprised\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Ella abriu a porta bruscamente. E l\\xe1 estava Marci. Descal\\xe7a. Cobertor azul escuro nos ombros como uma capa. Seus olhos arregalados demais.\",\n        next: \"ch1-021\"\n    },\n    \"ch1-021\": {\n        id: \"ch1-021\",\n        speaker: \"ella\",\n        text: \"Marci? Que diabos voc\\xea t\\xe1 fazendo no corredor \\xe0s duas da manh\\xe3?\",\n        next: \"ch1-022\"\n    },\n    \"ch1-022\": {\n        id: \"ch1-022\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"curious\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"worried\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Eu n\\xe3o consigo fechar os olhos.\",\n        next: \"ch1-023\"\n    },\n    \"ch1-023\": {\n        id: \"ch1-023\",\n        speaker: \"ella\",\n        text: \"Pesadelo?\",\n        next: \"ch1-024\"\n    },\n    \"ch1-024\": {\n        id: \"ch1-024\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"\\xc9 o oposto. Quando eu fecho... eu vejo. Tudo. Todo mundo. \\xc9 como ter os olhos abertos demais.\",\n        next: \"ch1-025\"\n    },\n    \"ch1-025\": {\n        id: \"ch1-025\",\n        speaker: null,\n        text: \"Ella a observou por um momento. Havia algo estranho em Marci naquela noite. Havia sempre algo estranho em Marci, mas daquela forma espec\\xedfica que voc\\xea s\\xf3 reconhecia quando o estranhamento falava com voc\\xea.\",\n        next: \"ch1-026\"\n    },\n    \"ch1-026\": {\n        id: \"ch1-026\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"confident\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Vem. A Maya sempre tem caf\\xe9.\",\n        next: \"ch1-027\"\n    },\n    \"ch1-027\": {\n        id: \"ch1-027\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"smiling-soft\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Ela nunca dorme, n\\xe9?\",\n        next: \"ch1-028\"\n    },\n    \"ch1-028\": {\n        id: \"ch1-028\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Nenhuma de n\\xf3s dorme. Pelo menos juntas a gente pode ser insone com companhia.\",\n        next: \"ch1-029\"\n    },\n    \"ch1-029\": {\n        id: \"ch1-029\",\n        speaker: null,\n        text: \"Ella estendeu a m\\xe3o. Marci a tomou. E assim, descal\\xe7as, cobertor e tudo mais, as duas caminh aram em dire\\xe7\\xe3o \\xe0 cozinha da Maya.\",\n        next: \"ch1-040\"\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // CAMINHO B: Ficar e ignorar → Encontra Maya depois\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch1-030\": {\n        id: \"ch1-030\",\n        background: \"cozinha-ella-noite\",\n        transition: \"none\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: null,\n        text: \"Os passos pararam. Ella esperou de p\\xe9, ainda segurando a \\xe1gua que tinha pego. Seu cora\\xe7\\xe3o batia com aquele ritmo que voc\\xea sente quando n\\xe3o faz nada e faz tudo ao mesmo tempo.\",\n        next: \"ch1-031\"\n    },\n    \"ch1-031\": {\n        id: \"ch1-031\",\n        speaker: null,\n        text: \"Sil\\xeancio. Apenas a chuva. Apenas o refrigerador zumbindo em seu canto.\",\n        next: \"ch1-032\"\n    },\n    \"ch1-032\": {\n        id: \"ch1-032\",\n        speaker: null,\n        text: \"Mas Ella n\\xe3o conseguia ficar. Algo a puxava — n\\xe3o para fora, mas para dentro. Para perto de outra pessoa.\",\n        next: \"ch1-033\"\n    },\n    \"ch1-033\": {\n        id: \"ch1-033\",\n        background: \"corredor-dormitorios-noite\",\n        transition: \"fade\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Ella saiu da cozinha, descal\\xe7a novamente. O corredor estava vazio.\",\n        next: \"ch1-034\"\n    },\n    \"ch1-034\": {\n        id: \"ch1-034\",\n        speaker: null,\n        text: \"Mas n\\xe3o estava silencioso. Havia um som de passos voltando. Diferentes daqueles que a acordaram.\",\n        next: \"ch1-035\"\n    },\n    \"ch1-035\": {\n        id: \"ch1-035\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Maya apareceu no corredor, vindo do seu quarto. Caneca na m\\xe3o. Cabelo preso em uma esp\\xe9cie de n\\xf3 que parecia estar lutando contra a escurid\\xe3o.\",\n        next: \"ch1-036\"\n    },\n    \"ch1-036\": {\n        id: \"ch1-036\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"surprised\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Jesus, Maya. Voc\\xea quase me mata de susto.\",\n        next: \"ch1-037\"\n    },\n    \"ch1-037\": {\n        id: \"ch1-037\",\n        sprites: {\n            right: {\n                char: \"maya\",\n                pose: \"looking-away\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Voc\\xea estava acordada?\",\n        next: \"ch1-038\"\n    },\n    \"ch1-038\": {\n        id: \"ch1-038\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Acordei. Pensei em ir \\xe0 cozinha da Maya buscar \\xe1gua, mas voc\\xea apareceu primeiro.\",\n        next: \"ch1-039\"\n    },\n    \"ch1-039\": {\n        id: \"ch1-039\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"thinking\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"sad\"\n            }\n        },\n        speaker: null,\n        text: \"Nesse momento, a porta de um dos quartos um pouco adiante abriu-se. Marci saiu, cobertor nos ombros, olhos demasiado abertos.\",\n        next: \"ch1-040\",\n        setFlag: \"encontru-maya-primeiro=true\"\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // CONVERGE: As três juntas, indo para a cozinha da Maya\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch1-040\": {\n        id: \"ch1-040\",\n        background: \"quarto-maya-noite\",\n        transition: \"fade\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"A porta da cozinha da Maya. Ella bateu. Maya abriu imediatamente — como se j\\xe1 estivesse esperando. Ela estava de p\\xe9, vestida, cabelo preso.\",\n        next: \"ch1-041\"\n    },\n    \"ch1-041\": {\n        id: \"ch1-041\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"curious\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"O caf\\xe9 t\\xe1 fresco.\",\n        next: \"ch1-042\"\n    },\n    \"ch1-042\": {\n        id: \"ch1-042\",\n        speaker: \"ella\",\n        text: \"Como voc\\xea sabia que a gente vinha?\",\n        next: \"ch1-043\"\n    },\n    \"ch1-043\": {\n        id: \"ch1-043\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Eu sempre tenho caf\\xe9 pronto. N\\xe3o \\xe9 previs\\xe3o. \\xc9 h\\xe1bito.\",\n        next: \"ch1-044\"\n    },\n    \"ch1-044\": {\n        id: \"ch1-044\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Maya... teu quarto \\xe9 t\\xe3o...\",\n        next: \"ch1-045\"\n    },\n    \"ch1-045\": {\n        id: \"ch1-045\",\n        speaker: \"maya\",\n        text: \"Vazio?\",\n        next: \"ch1-046\"\n    },\n    \"ch1-046\": {\n        id: \"ch1-046\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Exato. Vazio.\",\n        next: \"ch1-047\"\n    },\n    \"ch1-047\": {\n        id: \"ch1-047\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"looking-away\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"\\xc9 pr\\xe1tico. Quando voc\\xea sabe que pode ter que sair r\\xe1pido, n\\xe3o deixa muita coisa para levar.\",\n        next: \"ch1-048\"\n    },\n    \"ch1-048\": {\n        id: \"ch1-048\",\n        background: \"cozinha-maya-noite\",\n        transition: \"fade\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"A cozinha da Maya \\xe9 limpa, est\\xe9ril. S\\xf3 a cafeteira demonstra uso.\",\n        next: \"ch1-049\"\n    },\n    \"ch1-049\": {\n        id: \"ch1-049\",\n        speaker: null,\n        text: \"Maya serviu caf\\xe9. Tr\\xeas canecas. A chuva batendo na janela. O sil\\xeancio que se segue \\xe9 o sil\\xeancio de quem tem tudo para dizer e est\\xe1 esperando que outra pessoa comece.\",\n        next: \"ch1-050\"\n    },\n    \"ch1-050\": {\n        id: \"ch1-050\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"speaking\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"A comida do refeit\\xf3rio t\\xe1 cada vez pior ou eu que perdi o paladar durante o coma?\",\n        next: \"ch1-051\"\n    },\n    \"ch1-051\": {\n        id: \"ch1-051\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"happy\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"N\\xe3o, t\\xe1 pior mesmo. Na ter\\xe7a tinha um neg\\xf3cio que eles chamaram de strogonoff que parecia cola quente com corante.\",\n        next: \"ch1-052\"\n    },\n    \"ch1-052\": {\n        id: \"ch1-052\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Eu n\\xe3o como l\\xe1.\",\n        next: \"ch1-053\"\n    },\n    \"ch1-053\": {\n        id: \"ch1-053\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"happy\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Voc\\xea n\\xe3o come em lugar nenhum. Voc\\xea vive de caf\\xe9 e ressentimento c\\xf3smico.\",\n        next: \"ch1-054\"\n    },\n    \"ch1-054\": {\n        id: \"ch1-054\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"smiling-soft\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Ressentimento c\\xf3smico n\\xe3o tem caloria.\",\n        next: \"ch1-055\"\n    },\n    \"ch1-055\": {\n        id: \"ch1-055\",\n        speaker: \"ella\",\n        text: \"Por que nenhuma de n\\xf3s dorme?\",\n        next: \"ch1-056\"\n    },\n    \"ch1-056\": {\n        id: \"ch1-056\",\n        speaker: null,\n        text: \"Sil\\xeancio. O tipo de sil\\xeancio que tem peso.\",\n        next: \"ch1-057\"\n    },\n    \"ch1-057\": {\n        id: \"ch1-057\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"surprised\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Eu achei que era s\\xf3 eu.\",\n        next: \"ch1-058\"\n    },\n    \"ch1-058\": {\n        id: \"ch1-058\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"N\\xe3o \\xe9. A gente... a gente tem um problema em comum.\",\n        next: \"ch1-059\"\n    },\n    \"ch1-059\": {\n        id: \"ch1-059\",\n        speaker: null,\n        text: \"Ella olhou para Maya. Depois para Marci. O leite no caf\\xe9 subiu em pequenas redondezas brancas.\",\n        next: \"ch1-060\",\n        choices: [\n            {\n                text: \"Isso n\\xe3o \\xe9 normal, Maya. Voc\\xea precisa de ajuda.\",\n                next: \"ch1-070\",\n                setFlag: \"ella-protetora=true\"\n            },\n            {\n                text: \"Eu sei. Eu tamb\\xe9m n\\xe3o tenho dormido.\",\n                next: \"ch1-080\",\n                setFlag: \"ella-vulneravel=true\"\n            },\n            {\n                text: \"[Estende a m\\xe3o e aperta a de Maya]\",\n                next: \"ch1-090\",\n                setFlag: \"ella-silenciosa=true\"\n            }\n        ]\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // DECISÃO 2 - CAMINHO A: Ella protetora\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch1-070\": {\n        id: \"ch1-070\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"worried\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Isso n\\xe3o \\xe9 normal, Maya. Voc\\xea precisa de ajuda.\",\n        next: \"ch1-071\"\n    },\n    \"ch1-071\": {\n        id: \"ch1-071\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"angry\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Eu n\\xe3o preciso de ajuda. Eu preciso de respostas. S\\xe3o coisas diferentes.\",\n        next: \"ch1-072\"\n    },\n    \"ch1-072\": {\n        id: \"ch1-072\",\n        speaker: \"maya\",\n        text: \"A gente n\\xe3o dorme porque n\\xe3o consegue. E n\\xe3o consegue porque h\\xe1 algo aqui que n\\xe3o deixa.\",\n        next: \"ch2-001\"\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // DECISÃO 2 - CAMINHO B: Ella vulnerável\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch1-080\": {\n        id: \"ch1-080\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"sad\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"surprised\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Eu sei. Eu tamb\\xe9m n\\xe3o tenho dormido.\",\n        next: \"ch1-081\"\n    },\n    \"ch1-081\": {\n        id: \"ch1-081\",\n        speaker: \"maya\",\n        text: \"Voc\\xea tamb\\xe9m?\",\n        next: \"ch1-082\"\n    },\n    \"ch1-082\": {\n        id: \"ch1-082\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"looking-away\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"N\\xe3o \\xe9 a Ponte. Mas tamb\\xe9m n\\xe3o \\xe9 normal s\\xf3 cansa\\xe7o.\",\n        next: \"ch1-083\"\n    },\n    \"ch1-083\": {\n        id: \"ch1-083\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"A Ponte?\",\n        next: \"ch1-084\"\n    },\n    \"ch1-084\": {\n        id: \"ch1-084\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Eu... sim. A Ponte. Por isso eu n\\xe3o durmo. Quando fecho os olhos, ela t\\xe1 l\\xe1.\",\n        next: \"ch2-001\"\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // DECISÃO 2 - CAMINHO C: Ella silenciosa\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch1-090\": {\n        id: \"ch1-090\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"confident\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Ella n\\xe3o disse nada. Apenas estendeu a m\\xe3o pela mesa. Tomou a m\\xe3o de Maya. E a segurou.\",\n        next: \"ch1-091\"\n    },\n    \"ch1-091\": {\n        id: \"ch1-091\",\n        speaker: null,\n        text: \"Maya olhou para a m\\xe3o de Ella sobre a sua. N\\xe3o retirou. N\\xe3o comentou. Mas seus ombros descem um mil\\xedmetro — a postura relaxa sem que ela perceba.\",\n        next: \"ch1-092\"\n    },\n    \"ch1-092\": {\n        id: \"ch1-092\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: null,\n        text: \"Marci observa as duas em sil\\xeancio. Seus olhos brilham de um jeito que n\\xe3o \\xe9 completamente humano.\",\n        next: \"ch2-001\"\n    },\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    // CAPÍTULO 2 — \"CAFÉ ÀS DUAS\" (convergência)\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    \"ch2-001\": {\n        id: \"ch2-001\",\n        chapter: \"ch2\",\n        chapterTitle: \"CAF\\xc9 \\xc0S DUAS\",\n        speaker: \"maya\",\n        text: \"A gente n\\xe3o dorme porque n\\xe3o conseguimos aguentar o que vem quando fechamos os olhos.\",\n        next: \"ch2-002\"\n    },\n    \"ch2-002\": {\n        id: \"ch2-002\",\n        speaker: null,\n        text: 'Ela deixa a afirma\\xe7\\xe3o no ar como quem coloca um vidro quebrado na mesa e diz \"cuidado\".',\n        next: \"ch2-003\"\n    },\n    \"ch2-003\": {\n        id: \"ch2-003\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"serious\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"determined\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Eu vejo a Est\\xe1tua. Meu irm\\xe3o. E ele t\\xe1 me olhando de um jeito que me faz acordar ofegante.\",\n        next: \"ch2-004\"\n    },\n    \"ch2-004\": {\n        id: \"ch2-004\",\n        speaker: null,\n        text: \"Esse era um dos nomes que elle n\\xe3o falava em voz alta. Niuw\\xeb. O irm\\xe3o que morreu 143 dias atr\\xe1s.\",\n        next: \"ch2-005\"\n    },\n    \"ch2-005\": {\n        id: \"ch2-005\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Eu ou\\xe7o H\\xe4ita. N\\xe3o uma voz. \\xc9 mais como... uma press\\xe3o. Aqui.\",\n        next: \"ch2-006\"\n    },\n    \"ch2-006\": {\n        id: \"ch2-006\",\n        speaker: \"maya\",\n        text: \"Como se algu\\xe9m estivesse apertando meu peito de dentro. E desse aperto saem palavras. N\\xe3o as minhas.\",\n        next: \"ch2-007\"\n    },\n    \"ch2-007\": {\n        id: \"ch2-007\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"worried\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"O que ela te diz?\",\n        next: \"ch2-008\"\n    },\n    \"ch2-008\": {\n        id: \"ch2-008\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"sad\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Que t\\xe1 cansada. E quando uma deusa fica cansada... o que vem depois?\",\n        next: \"ch2-009\"\n    },\n    \"ch2-009\": {\n        id: \"ch2-009\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Sil\\xeancio.\",\n        next: \"ch2-010\"\n    },\n    \"ch2-010\": {\n        id: \"ch2-010\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Exato. Sil\\xeancio. E sil\\xeancio de uma coisa t\\xe3o antiga como H\\xe4ita n\\xe3o \\xe9 paz. \\xc9 antes de tudo desabar.\",\n        next: \"ch2-011\",\n        choices: [\n            {\n                text: \"Como voc\\xea pode ter tanta certeza disso?\",\n                next: \"ch2-020\",\n                setFlag: \"confrontou-conhecimento=true\"\n            },\n            {\n                text: \"[Apenas escuta. Deixa o peso das palavras deitar-se como chuva]\",\n                next: \"ch2-030\",\n                setFlag: \"ouviu-silenciosa=true\"\n            }\n        ]\n    },\n    \"ch2-020\": {\n        id: \"ch2-020\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Como voc\\xea pode ter tanta certeza disso, Maya?\",\n        next: \"ch2-021\"\n    },\n    \"ch2-021\": {\n        id: \"ch2-021\",\n        speaker: \"maya\",\n        text: \"Por que ela me conta. Porque \\xe9 meu sangue que carrega isso. Porque meu corpo \\xe9 uma antena e meu quarto \\xe9 o cais onde a deusa doca quando cansa de nadar.\",\n        next: \"ch2-030\"\n    },\n    \"ch2-030\": {\n        id: \"ch2-030\",\n        speaker: \"ella\",\n        text: \"Eu venho aqui toda noite. Pedir desculpa por estar viva.\",\n        next: \"ch2-031\"\n    },\n    \"ch2-031\": {\n        id: \"ch2-031\",\n        speaker: null,\n        text: \"O sil\\xeancio que se segue n\\xe3o \\xe9 vazio. \\xc9 full. Cheio de todos os 143 dias somados em um instante de press\\xe3o.\",\n        next: \"ch2-032\"\n    },\n    \"ch2-032\": {\n        id: \"ch2-032\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Voc\\xea pede desculpa todo dia?\",\n        next: \"ch2-033\"\n    },\n    \"ch2-033\": {\n        id: \"ch2-033\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"sad\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Vou pra l\\xe1 \\xe0s tr\\xeas da manh\\xe3. Sento na base da est\\xe1tua. Falo com ele. Conto o dia. O que eu comi. O que o professor falou. Bobagens.\",\n        next: \"ch2-034\"\n    },\n    \"ch2-034\": {\n        id: \"ch2-034\",\n        speaker: \"ella\",\n        text: \"E depois pe\\xe7o desculpa por estar aqui contando bobagens em vez de estar onde ele est\\xe1.\",\n        next: \"ch2-035\"\n    },\n    \"ch2-035\": {\n        id: \"ch2-035\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Ella...\",\n        next: \"ch2-036\"\n    },\n    \"ch2-036\": {\n        id: \"ch2-036\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"N\\xe3o tenta me dizer que n\\xe3o \\xe9 minha culpa. Eu sei que n\\xe3o \\xe9. Mas saber e sentir s\\xe3o coisas diferentes, Maya. Voc\\xea de todas as pessoas deveria saber isso.\",\n        next: \"ch2-037\"\n    },\n    \"ch2-037\": {\n        id: \"ch2-037\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"looking-away\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"...\",\n        next: \"ch2-038\"\n    },\n    \"ch2-038\": {\n        id: \"ch2-038\",\n        speaker: null,\n        text: \"Maya n\\xe3o responde. Porque Ella tem raz\\xe3o. E a raz\\xe3o \\xe9 o tipo de coisa que pesa mais quando ningu\\xe9m discorda.\",\n        next: \"ch2-040\"\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // A confissão de Marci — DECISÃO CRÍTICA\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch2-040\": {\n        id: \"ch2-040\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Marci estava olhando para o caf\\xe9 esfriando na caneca. Havia algo em sua express\\xe3o que dizia: agora \\xe9 a minha vez.\",\n        next: \"ch2-041\"\n    },\n    \"ch2-041\": {\n        id: \"ch2-041\",\n        speaker: \"marci\",\n        text: \"Eu tenho uma coisa pra contar.\",\n        next: \"ch2-042\"\n    },\n    \"ch2-042\": {\n        id: \"ch2-042\",\n        speaker: null,\n        text: \"Ella e Maya a olham simultaneamente. Isso nunca \\xe9 um bom sinal.\",\n        next: \"ch2-043\",\n        choices: [\n            {\n                text: \"Voc\\xea n\\xe3o precisa contar se n\\xe3o quiser.\",\n                next: \"ch2-050\",\n                setFlag: \"gentil-com-marci=true\"\n            },\n            {\n                text: \"A gente contou. Sua vez.\",\n                next: \"ch2-055\",\n                setFlag: \"direta-com-marci=true\"\n            }\n        ]\n    },\n    \"ch2-050\": {\n        id: \"ch2-050\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Voc\\xea n\\xe3o precisa contar se n\\xe3o quiser. Ningu\\xe9m nunca pediu isso.\",\n        next: \"ch2-051\"\n    },\n    \"ch2-051\": {\n        id: \"ch2-051\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"smiling-soft\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Mas eu preciso. Eu acho que \\xe9 por isso que a gente t\\xe1 acordada. A gente precisava ouvir uma \\xe0 outra.\",\n        next: \"ch2-055\"\n    },\n    \"ch2-055\": {\n        id: \"ch2-055\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Durante os tr\\xeas anos que eu fiquei em coma... eu tava acordada.\",\n        next: \"ch2-056\"\n    },\n    \"ch2-056\": {\n        id: \"ch2-056\",\n        speaker: null,\n        text: \"O sil\\xeancio que se segue \\xe9 de um tipo diferente. \\xc9 o sil\\xeancio que antecede o ponto de quebra.\",\n        next: \"ch2-057\"\n    },\n    \"ch2-057\": {\n        id: \"ch2-057\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"N\\xe3o sonhando. N\\xe3o dormindo. Assistindo. Vi cada batalha. Vi cada conversa. Vi voc\\xeas sofrerem.\",\n        next: \"ch2-058\"\n    },\n    \"ch2-058\": {\n        id: \"ch2-058\",\n        speaker: \"marci\",\n        text: \"E n\\xe3o podia falar, n\\xe3o podia me mover, n\\xe3o podia gritar.\",\n        next: \"ch2-059\"\n    },\n    \"ch2-059\": {\n        id: \"ch2-059\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"shocked\"\n            }\n        },\n        speaker: null,\n        text: \"Ella gelou. Gelou de uma forma que n\\xe3o era frio. Era reconhecimento.\",\n        next: \"ch2-060\"\n    },\n    \"ch2-060\": {\n        id: \"ch2-060\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Eu vi a Ella sentada na base da est\\xe1tua na ter\\xe7a-feira passada. Voc\\xea estava de moletom cinza. Chorou por onze minutos.\",\n        next: \"ch2-061\"\n    },\n    \"ch2-061\": {\n        id: \"ch2-061\",\n        speaker: \"marci\",\n        text: \"Depois limpou o rosto e voltou. Voc\\xea pensou que ningu\\xe9m tava vendo.\",\n        next: \"ch2-062\"\n    },\n    \"ch2-062\": {\n        id: \"ch2-062\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"scared\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Isso... isso foi ter\\xe7a.\",\n        next: \"ch2-063\"\n    },\n    \"ch2-063\": {\n        id: \"ch2-063\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Eu sei.\",\n        next: \"ch2-064\"\n    },\n    \"ch2-064\": {\n        id: \"ch2-064\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Eu vi a Maya tomando os comprimidos. Tr\\xeas de uma vez. No banheiro. Com a porta trancada. Voc\\xea a\\xe7ordou \\xe0s 4h23 chorando.\",\n        next: \"ch2-065\"\n    },\n    \"ch2-065\": {\n        id: \"ch2-065\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"rigid\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Marci.\",\n        next: \"ch2-066\"\n    },\n    \"ch2-066\": {\n        id: \"ch2-066\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"serious\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"sad\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Durante tr\\xeas anos, tudo que eu podia fazer era assistir voc\\xeas sofrerem e gritar dentro de um corpo que n\\xe3o me obedecia. Entendo agora por que voc\\xeas n\\xe3o dormem.\",\n        next: \"ch2-067\"\n    },\n    \"ch2-067\": {\n        id: \"ch2-067\",\n        speaker: null,\n        text: \"O caf\\xe9 esfriou completamente. Ningu\\xe9m se move. O peso de seus conhecimentos m\\xfatuos desabobalogiza a cozinha inteira.\",\n        next: \"ch2-068\",\n        choices: [\n            {\n                text: \"H\\xe4ita fez isso com voc\\xea.\",\n                next: \"ch2-075\",\n                setFlag: \"culpou-haita=true\"\n            },\n            {\n                text: \"Voc\\xea ainda est\\xe1 assistindo?\",\n                next: \"ch2-085\",\n                setFlag: \"questionou-marci=true\"\n            }\n        ]\n    },\n    \"ch2-075\": {\n        id: \"ch2-075\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"determined\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"H\\xe4ita. Foi ela que fez isso. Voc\\xea t\\xe1 conectada a ela tamb\\xe9m.\",\n        next: \"ch2-076\"\n    },\n    \"ch2-076\": {\n        id: \"ch2-076\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Talvez. Ou talvez a gente t\\xe1 todas conectadas e ningu\\xe9m queria saber. Quando voc\\xea acorda de um coma, as regras mudam.\",\n        next: \"ch3-001\"\n    },\n    \"ch2-085\": {\n        id: \"ch2-085\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"serious\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Voc\\xea ainda est\\xe1 assistindo?\",\n        next: \"ch2-086\"\n    },\n    \"ch2-086\": {\n        id: \"ch2-086\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Eu... n\\xe3o sei. \\xc0s vezes coisas aparecem na minha cabe\\xe7a que n\\xe3o s\\xe3o minhas.\",\n        next: \"ch2-087\"\n    },\n    \"ch2-087\": {\n        id: \"ch2-087\",\n        speaker: \"marci\",\n        text: \"\\xc9 como r\\xe1dio sintonizado na frequ\\xeancia errada. Vem som. Vem imagem. Vem sensa\\xe7\\xe3o.\",\n        next: \"ch2-088\"\n    },\n    \"ch2-088\": {\n        id: \"ch2-088\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Voc\\xea t\\xe1 absorvendo coisas. Do espa\\xe7o entre mundos. Voc\\xea ficou l\\xe1 por tr\\xeas anos. Voc\\xea trouxe coisa de volta.\",\n        next: \"ch2-089\"\n    },\n    \"ch2-089\": {\n        id: \"ch2-089\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"scared\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"O que traz de volta de um lugar assim, Maya?\",\n        next: \"ch2-090\"\n    },\n    \"ch2-090\": {\n        id: \"ch2-090\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"N\\xe3o sei. Mas depois voc\\xea me diz.\",\n        background: \"\",\n        next: \"ch3-001\"\n    },\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    // CAPÍTULO 3 — \"O QUE O ESCURO MOSTRA\"\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    \"ch3-001\": {\n        id: \"ch3-001\",\n        background: \"biblioteca-noite\",\n        transition: \"fade\",\n        chapter: \"ch3\",\n        chapterTitle: \"O QUE O ESCURO MOSTRA\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"A biblioteca vazia \\xe0 noite \\xe9 um lugar que faz voc\\xea se sentir como invasor de um templo. Maya abre um dos livros sobre H\\xe4ita. Folheia at\\xe9 encontrar a passagem que procura.\",\n        next: \"ch3-002\"\n    },\n    \"ch3-002\": {\n        id: \"ch3-002\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"reading\"\n            }\n        },\n        speaker: \"maya\",\n        text: '\"H\\xe4ita n\\xe3o escolhe os fortes. Ela escolhe os que aguentam. E aguentar n\\xe3o \\xe9 a mesma coisa que n\\xe3o quebrar.\"',\n        next: \"ch3-003\"\n    },\n    \"ch3-003\": {\n        id: \"ch3-003\",\n        speaker: \"maya\",\n        text: '\"\\xc9 quebrar e continuar de p\\xe9 com os peda\\xe7os nas m\\xe3os.\"',\n        next: \"ch3-004\"\n    },\n    \"ch3-004\": {\n        id: \"ch3-004\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"sad\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Ent\\xe3o a gente \\xe9 isso. Tr\\xeas meninas quebradas segurando os peda\\xe7os.\",\n        next: \"ch3-005\"\n    },\n    \"ch3-005\": {\n        id: \"ch3-005\",\n        speaker: null,\n        text: \"A biblioteca est\\xe1 silenciosa demais. \\xc9 o sil\\xeancio que pesa.\",\n        next: \"ch3-006\",\n        choices: [\n            {\n                text: \"Quebradas, n\\xe3o. Rachadas. Rachado ainda segura.\",\n                next: \"ch3-010\",\n                setFlag: \"aceitou-haita=true\"\n            },\n            {\n                text: \"Foda-se a deusa. A gente segura porque a gente segura. N\\xe3o por ela.\",\n                next: \"ch3-020\",\n                setFlag: \"rejeitou-haita=true\"\n            }\n        ]\n    },\n    \"ch3-010\": {\n        id: \"ch3-010\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"determined\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Quebradas, n\\xe3o. Rachadas. Rachado ainda segura. Rachado ainda deixa luz passar.\",\n        next: \"ch3-011\"\n    },\n    \"ch3-011\": {\n        id: \"ch3-011\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"smiling-soft\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Voc\\xea tem raz\\xe3o. R\\xe4che deixa passar coisas que vidro inteiro n\\xe3o consegue deixar.\",\n        next: \"ch3-012\"\n    },\n    \"ch3-012\": {\n        id: \"ch3-012\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"arms-crossed\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"E \\xe9 por isso que a gente n\\xe3o dorme. Porque h\\xe1 fissuras demais pra bloquear.\",\n        next: \"ch3-030\"\n    },\n    \"ch3-020\": {\n        id: \"ch3-020\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"angry\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Foda-se a deusa. A gente segura porque a gente segura. N\\xe3o por ela. N\\xe3o por ningu\\xe9m al\\xe9m de n\\xf3s mesmas.\",\n        next: \"ch3-021\"\n    },\n    \"ch3-021\": {\n        id: \"ch3-021\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"determined\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Eu queria ter essa raiva.\",\n        next: \"ch3-022\"\n    },\n    \"ch3-022\": {\n        id: \"ch3-022\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"serious\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"N\\xe3o \\xe9 raiva. \\xc9 escolha. Eu n\\xe3o preciso de uma deusa pra justificar o que eu sinto pelas pessoas que t\\xe3o do meu lado.\",\n        next: \"ch3-023\"\n    },\n    \"ch3-023\": {\n        id: \"ch3-023\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"smiling-soft\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Ent\\xe3o escolha \\xe9 o que voc\\xea chama isso.\",\n        next: \"ch3-030\"\n    },\n    \"ch3-030\": {\n        id: \"ch3-030\",\n        speaker: null,\n        text: \"A hora muda. Sem que ningu\\xe9m repare, o tempo passou de 4 da manh\\xe3 para 5 e meia.\",\n        next: \"ch3-031\"\n    },\n    \"ch3-031\": {\n        id: \"ch3-031\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"looking-away\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"thinking\"\n            }\n        },\n        speaker: null,\n        text: \"As tr\\xeas est\\xe3o sentadas na biblioteca sob luz azulada de fluorescente vencido. Fora, o Pac\\xedfico continua n\\xe3o dormindo tamb\\xe9m.\",\n        next: \"ch3-032\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-032\": {\n        id: \"ch3-032\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Marci fecha os olhos. Seus dedos tamborilam na mesa com uma precis\\xe3o que n\\xe3o deveria ter.\",\n        next: \"ch3-033\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-033\": {\n        id: \"ch3-033\",\n        background: \"dentalia\",\n        transition: \"flash-white\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"scared\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"scared\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"O cen\\xe1rio mudar. Subitamente. Sem transi\\xe7\\xe3o.\",\n        next: \"ch3-034\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-034\": {\n        id: \"ch3-034\",\n        speaker: null,\n        text: \"Void. Sil\\xeancio. As tr\\xeas paradas juntas em um lugar que n\\xe3o \\xe9 um lugar.\",\n        next: \"ch3-035\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-035\": {\n        id: \"ch3-035\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"scared\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Onde a gente... onde a gente t\\xe1?\",\n        next: \"ch3-036\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-036\": {\n        id: \"ch3-036\",\n        sprites: {\n            center: {\n                char: \"maya\",\n                pose: \"surprised\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"A Ponte. \\xc9 a Ponte.\",\n        next: \"ch3-037\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-037\": {\n        id: \"ch3-037\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"N\\xe3o tenham medo. Eu estou aqui. Eu sempre estou.\",\n        next: \"ch3-038\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-038\": {\n        id: \"ch3-038\",\n        background: \"biblioteca-noite\",\n        transition: \"flash-white\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"surprised\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"surprised\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"De volta. Subitamente. A biblioteca volta como se nunca tivessem sa\\xeddo.\",\n        next: \"ch3-039\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-039\": {\n        id: \"ch3-039\",\n        sprites: {\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"Desculpa. \\xc0s vezes... escapa.\",\n        next: \"ch3-040\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch3-040\": {\n        id: \"ch3-040\",\n        speaker: null,\n        text: \"Ningu\\xe9m diz nada por um tempo que n\\xe3o \\xe9 medido em minutos. \\xc9 medido em batidas de cora\\xe7\\xe3o.\",\n        sound: \"silence\",\n        next: \"ch4-001\"\n    },\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    // CAPÍTULO 4 — \"TRÊS MANEIRAS DE NÃO DORMIR\"\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    \"ch4-001\": {\n        id: \"ch4-001\",\n        background: \"externa-dormitorios-noite-escura\",\n        transition: \"fade\",\n        chapter: \"ch4\",\n        chapterTitle: \"TR\\xcaS MANEIRAS DE N\\xc3O DORMIR\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"3h30. As tr\\xeas saem da biblioteca. Caminham pelo campus.\",\n        next: \"ch4-002\"\n    },\n    \"ch4-002\": {\n        id: \"ch4-002\",\n        speaker: null,\n        text: \"O ar salgado do Pac\\xedfico. Brisa tropical. \\xc1rvores criando sombras que parecem se mover.\",\n        next: \"ch4-003\"\n    },\n    \"ch4-003\": {\n        id: \"ch4-003\",\n        speaker: null,\n        text: \"Catat\\xfania \\xe9 um lugar que foi poupado do fim do mundo. Ainda n\\xe3o sabe se agradece por isso.\",\n        next: \"ch4-004\"\n    },\n    \"ch4-004\": {\n        id: \"ch4-004\",\n        speaker: null,\n        text: \"Tr\\xeas silhuetas em sil\\xeancio. Depois de tanto peso, o sil\\xeancio \\xe9 diferente.\",\n        next: \"ch4-005\"\n    },\n    \"ch4-005\": {\n        id: \"ch4-005\",\n        speaker: null,\n        text: \"N\\xe3o \\xe9 vazio. \\xc9 cheio. Como o sil\\xeancio depois de um temporal quando a chuva para e o mundo t\\xe1 lavado.\",\n        next: \"ch4-006\"\n    },\n    \"ch4-006\": {\n        id: \"ch4-006\",\n        background: \"estatua-imortais-noite-escura\",\n        transition: \"fade\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"sad\"\n            }\n        },\n        speaker: null,\n        text: \"A est\\xe1tua de Niuw\\xeb, Selenna e Mensa-Vikt\\xf6r. Ella para.\",\n        next: \"ch4-007\"\n    },\n    \"ch4-007\": {\n        id: \"ch4-007\",\n        speaker: null,\n        text: \"\\xc0 noite, o metal escuro absorve a escurid\\xe3o. As tr\\xeas figuras adolescentes parecem mais jovens. Mais vulner\\xe1veis.\",\n        next: \"ch4-008\"\n    },\n    \"ch4-008\": {\n        id: \"ch4-008\",\n        speaker: null,\n        text: \"Como se a escurid\\xe3o tirasse a grandiosidade e devolvesse a idade real deles.\",\n        next: \"ch4-009\"\n    },\n    \"ch4-009\": {\n        id: \"ch4-009\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"looking-away\"\n            },\n            left: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Ella olha para o rosto que \\xe9 como o seu. O rosto de metal do irm\\xe3o.\",\n        next: \"ch4-010\",\n        choices: [\n            {\n                text: \"Tocando a base, encontrando perd\\xe3o\",\n                next: \"ch4-020\",\n                setFlag: \"ella-cresceu=true\"\n            },\n            {\n                text: \"Afastando, n\\xe3o conseguindo conforto\",\n                next: \"ch4-050\",\n                setFlag: \"ella-fugiu=true\"\n            }\n        ]\n    },\n    \"ch4-020\": {\n        id: \"ch4-020\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"confident\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Eu venho aqui toda noite pedir desculpa por estar viva.\",\n        next: \"ch4-021\"\n    },\n    \"ch4-021\": {\n        id: \"ch4-021\",\n        speaker: \"ella\",\n        text: \"Mas hoje... hoje n\\xe3o quero pedir desculpa.\",\n        next: \"ch4-022\"\n    },\n    \"ch4-022\": {\n        id: \"ch4-022\",\n        speaker: null,\n        text: \"Ella toca a base da est\\xe1tua. N\\xe3o fala com Niuw\\xeb. Apenas toca.\",\n        next: \"ch4-023\"\n    },\n    \"ch4-023\": {\n        id: \"ch4-023\",\n        speaker: null,\n        text: \"Maya e Marci ficam a alguns passos. Esperando. Entendendo sem precisar de palavras.\",\n        next: \"ch4-024\"\n    },\n    \"ch4-024\": {\n        id: \"ch4-024\",\n        speaker: null,\n        text: \"Pela primeira vez em 143 noites, Ella n\\xe3o pediu desculpa. Desculpa pela morte dele. Desculpa por estar viva.\",\n        next: \"ch4-025\"\n    },\n    \"ch4-025\": {\n        id: \"ch4-025\",\n        speaker: null,\n        text: \"N\\xe3o porque a culpa tivesse ido embora. Mas porque naquela noite ela n\\xe3o estava sozinha ao carreg\\xe1-la.\",\n        next: \"ch4-030\"\n    },\n    \"ch4-050\": {\n        id: \"ch4-050\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"sad\"\n            },\n            left: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"ella\",\n        text: \"Vamos. N\\xe3o quero ficar aqui.\",\n        next: \"ch4-051\"\n    },\n    \"ch4-051\": {\n        id: \"ch4-051\",\n        sprites: {\n            center: null,\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: \"maya\",\n        text: \"Ok. A gente vai.\",\n        next: \"ch4-052\"\n    },\n    \"ch4-052\": {\n        id: \"ch4-052\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Ella se afasta r\\xe1pido. Maya a segue.\",\n        next: \"ch4-053\"\n    },\n    \"ch4-053\": {\n        id: \"ch4-053\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"marci\",\n                pose: \"thinking\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Marci olha para a est\\xe1tua um momento a mais do que o comum. Como se os tr\\xeas guerreiros de metal estivessem lhe dizendo algo que s\\xf3 ela consegue ouvir.\",\n        next: \"ch4-054\"\n    },\n    \"ch4-054\": {\n        id: \"ch4-054\",\n        background: \"externa-dormitorios-nublado\",\n        transition: \"fade\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"marci\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"Marci segue as amigas.\",\n        next: \"ch4-030\"\n    },\n    \"ch4-030\": {\n        id: \"ch4-030\",\n        background: \"biblioteca-noite\",\n        transition: \"fade\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"De volta \\xe0 biblioteca. Ou nunca sa\\xedram? O tempo en Catat\\xfania n\\xe3o \\xe9 linear quando voc\\xea n\\xe3o dorme.\",\n        next: \"ch4-031\"\n    },\n    \"ch4-031\": {\n        id: \"ch4-031\",\n        speaker: null,\n        text: \"A conversa foi morrendo naturalmente. N\\xe3o porque acabou, mas porque o corpo tem limites.\",\n        next: \"ch4-032\"\n    },\n    \"ch4-032\": {\n        id: \"ch4-032\",\n        speaker: null,\n        text: \"As tr\\xeas ficaram aqui at\\xe9 o amanhecer.\",\n        next: \"ch4-033\"\n    },\n    \"ch4-033\": {\n        id: \"ch4-033\",\n        speaker: null,\n        text: \"O c\\xe9u muda de cor pela janela da biblioteca. De preto para cinza-rosa.\",\n        next: \"ch4-034\"\n    },\n    \"ch4-034\": {\n        id: \"ch4-034\",\n        speaker: null,\n        text: \"N\\xe3o vermelho. N\\xe3o desta vez. Apenas o cinza honesto de uma manh\\xe3 nublada em uma ilha no Pac\\xedfico.\",\n        next: \"ch5-001\"\n    },\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    // CAPÍTULO 5 — \"AMANHECER\"\n    // ═══════════════════════════════════════════════════════════════════════════════════\n    \"ch5-001\": {\n        id: \"ch5-001\",\n        background: \"externa-dormitorios-nublado\",\n        transition: \"fade\",\n        chapter: \"ch5\",\n        chapterTitle: \"AMANHECER\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"marci\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"O amanhecer chegou sem pedir permiss\\xe3o. Como faz.\",\n        next: \"ch5-002\"\n    },\n    \"ch5-002\": {\n        id: \"ch5-002\",\n        speaker: null,\n        text: \"Caminham de volta. O campus est\\xe1 acordando. Pessoas normais come\\xe7ando um dia normal.\",\n        next: \"ch5-003\"\n    },\n    \"ch5-003\": {\n        id: \"ch5-003\",\n        speaker: null,\n        text: \"As tr\\xeas em sil\\xeancio. Mas \\xe9 um sil\\xeancio diferente do in\\xedcio da noite.\",\n        next: \"ch5-004\"\n    },\n    \"ch5-004\": {\n        id: \"ch5-004\",\n        speaker: null,\n        text: \"\\xc9 o sil\\xeancio de quem disse o que precisava dizer.\",\n        next: \"ch5-005\"\n    },\n    \"ch5-005\": {\n        id: \"ch5-005\",\n        speaker: null,\n        text: \"Na frente dos dormit\\xf3rios. Antes de se separarem. O caminho se divide novamente.\",\n        next: \"ch5-006\"\n    },\n    \"ch5-006\": {\n        id: \"ch5-006\",\n        sprites: {\n            center: {\n                char: \"marci\",\n                pose: \"speaking\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"A gente podia fazer isso de novo. Assado noites, dormindo seguran\\xe7a em companhia.\",\n        next: \"ch5-007\"\n    },\n    \"ch5-007\": {\n        id: \"ch5-007\",\n        sprites: {\n            center: {\n                char: \"marci\",\n                pose: \"smiling-soft\"\n            }\n        },\n        speaker: \"marci\",\n        text: \"S\\xf3 o caf\\xe9. S\\xf3 voc\\xeas.\",\n        next: \"ch5-008\",\n        choices: [\n            {\n                text: \"Toda noite que eu n\\xe3o conseguir dormir, a porta da minha cozinha t\\xe1 aberta.\",\n                next: \"ch5-final-setup\",\n                setFlag: \"promise-aberta=true\"\n            },\n            {\n                text: \"Amanh\\xe3. Mesma hora. Sem desculpas.\",\n                next: \"ch5-final-setup\",\n                setFlag: \"promise-determinada=true\"\n            },\n            {\n                text: \"[Abra\\xe7a as duas sem dizer nada]\",\n                next: \"ch5-final-setup\",\n                setFlag: \"promise-abraco=true\"\n            }\n        ]\n    },\n    // ─────────────────────────────────────────────────────────────────────────────────\n    // Lógica de Endings\n    // ─────────────────────────────────────────────────────────────────────────────────\n    \"ch5-final-setup\": {\n        id: \"ch5-final-setup\",\n        speaker: null,\n        text: \"O amanhecer continua. As tr\\xeas se olham. \\xc9 tempo de escolher.\",\n        next: \"ch5-route-picker\"\n    },\n    \"ch5-route-picker\": {\n        id: \"ch5-route-picker\",\n        speaker: null,\n        text: \"\",\n        condition: {\n            flag: \"questionou-marci\",\n            value: true\n        },\n        next: \"ch5-ending-assistindo\"\n    },\n    \"ch5-route-picker-alt\": {\n        id: \"ch5-route-picker-alt\",\n        speaker: null,\n        text: \"\",\n        condition: {\n            flag: \"rejeitou-haita\",\n            value: true\n        },\n        next: \"ch5-ending-sem-deusa\"\n    },\n    \"ch5-route-picker-default\": {\n        id: \"ch5-route-picker-default\",\n        speaker: null,\n        text: \"\",\n        next: \"ch5-ending-rachadas\"\n    },\n    \"ch5-ending-rachadas\": {\n        id: \"ch5-ending-rachadas\",\n        background: \"estatua-imortais-nublado\",\n        transition: \"fade\",\n        chapter: \"ch5\",\n        chapterTitle: \"AMANHECER\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"confident\"\n            }\n        },\n        speaker: null,\n        text: \"Ella olha para a est\\xe1tua de manh\\xe3 pela primeira vez sem culpa. O metal brilha sob o sol nublado.\",\n        next: \"ch5-ending-rachadas-02\",\n        ending: \"rachadas\"\n    },\n    \"ch5-ending-rachadas-02\": {\n        id: \"ch5-ending-rachadas-02\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"confident\"\n            }\n        },\n        speaker: null,\n        text: \"Tr\\xeas meninas rachadas. Segurando os peda\\xe7os umas das outras. N\\xe3o porque uma deusa mandou. N\\xe3o porque o destino exigiu.\",\n        next: \"ch5-ending-rachadas-03\",\n        ending: \"rachadas\"\n    },\n    \"ch5-ending-rachadas-03\": {\n        id: \"ch5-ending-rachadas-03\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"confident\"\n            }\n        },\n        speaker: null,\n        text: \"Porque \\xe0s duas da manh\\xe3, quando o peso \\xe9 demais para uma pessoa, tr\\xeas caf\\xe9s amargos e uma cozinha vazia s\\xe3o suficientes para aguentar mais uma noite.\",\n        next: \"ch5-ending-rachadas-04\",\n        ending: \"rachadas\"\n    },\n    \"ch5-ending-rachadas-04\": {\n        id: \"ch5-ending-rachadas-04\",\n        sprites: {\n            center: {\n                char: \"ella\",\n                pose: \"confident\"\n            }\n        },\n        speaker: null,\n        text: \"E amanh\\xe3, quando a ins\\xf4nia voltar — porque vai voltar — a porta vai estar aberta.\",\n        ending: \"rachadas\"\n    },\n    \"ch5-ending-sem-deusa\": {\n        id: \"ch5-ending-sem-deusa\",\n        background: \"externa-dormitorios-nublado\",\n        transition: \"fade\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"marci\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"maya\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"As tr\\xeas se separam com um aceno. Sem abra\\xe7o. Sem promessa verbalizada.\",\n        ending: \"sem-deusa\",\n        next: \"ch5-ending-sem-deusa-02\"\n    },\n    \"ch5-ending-sem-deusa-02\": {\n        id: \"ch5-ending-sem-deusa-02\",\n        speaker: null,\n        text: \"Mas com o entendimento silencioso de que aquilo vai se repetir. Toda noite. Enquanto precisarem.\",\n        ending: \"sem-deusa\",\n        next: \"ch5-ending-sem-deusa-03\"\n    },\n    \"ch5-ending-sem-deusa-03\": {\n        id: \"ch5-ending-sem-deusa-03\",\n        speaker: null,\n        text: \"H\\xe4ita pode ter escolhido elas. Mas elas escolheram umas \\xe0s outras. E isso \\xe9 mais.\",\n        ending: \"sem-deusa\"\n    },\n    \"ch5-ending-assistindo\": {\n        id: \"ch5-ending-assistindo\",\n        background: \"dentalia\",\n        transition: \"fade\",\n        sprites: {\n            left: {\n                char: \"ella\",\n                pose: \"neutral\"\n            },\n            center: {\n                char: \"maya\",\n                pose: \"neutral\"\n            },\n            right: {\n                char: \"marci\",\n                pose: \"neutral\"\n            }\n        },\n        speaker: null,\n        text: \"As tr\\xeas se separam. Ella e Maya entram. Marci fica.\",\n        ending: \"assistindo\",\n        next: \"ch5-ending-assistindo-02\",\n        condition: {\n            flag: \"confrontou-marci\",\n            value: true\n        }\n    },\n    \"ch5-ending-assistindo-02\": {\n        id: \"ch5-ending-assistindo-02\",\n        speaker: null,\n        text: \"Marci sorri. N\\xe3o \\xe9 um sorriso humano.\",\n        ending: \"assistindo\",\n        next: \"ch5-ending-assistindo-03\"\n    },\n    \"ch5-ending-assistindo-03\": {\n        id: \"ch5-ending-assistindo-03\",\n        speaker: null,\n        text: \"Eu vejo tudo. Sempre vi. E vou continuar vendo.\",\n        ending: \"assistindo\",\n        next: \"ch5-ending-assistindo-04\"\n    },\n    \"ch5-ending-assistindo-04\": {\n        id: \"ch5-ending-assistindo-04\",\n        speaker: null,\n        text: \"Blackout.\",\n        ending: \"assistindo\"\n    }\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./data/story.ts\n");

